    #{fids}

SELECT pbh.fbill_no, pbh.fdocument_status, pbh.fdate, sr.name as fsupplier_id, su.user_name as fcreator_id, pbh.fcreate_date, pbh.fmodifier_id, pbh.fmodify_date, pbh.fapprover_id, pbh.fapprove_date, pbh.fcanceller_id, pbh.fcancel_date, pbh.fclose_status, pbh.fcloser_id, pbh.fclose_date, bd.name as fbill_type_id, ser.name as fsettle_id, spr.name as fcharge_id, pbh.fchanger_id, pbh.fchange_date, pbh.fchange_reason, pbh.fbusiness_type, pbh.fprovider_address, pbh.fassign_supplier_id, pbh.fconfirm_status, pbh.fconfirmer_id, pbh.fconfirm_date, sc.contact_name as fprovider_contact_id, pbh.fprovider_job, pbh.fprovider_phone, pbh.fsource_bill_no, pbh.fchange_status, pbh.facctype, pbh.fprovider_email, pbh.fclose_reason, pbh.fcontract_type, pbh.f_ypdd, pbh.f_ora_date, pbh.f_zlbz, pbh.f_zmtp1, pbh.f_zmtp2, pbh.f_zmtp3, pbh.f_zmtxm, pbh.f_zmms, pbh.f_cmtp1, pbh.f_cmtp2, pbh.f_cmms, pbh.f_cmtxm, pbh.f_bzbzjyq, pbh.f_kh, pbh.f_jjdbl, pbh.f_gxhth, pbh.f_khjc, pbh.f_zje, se.fname as f_gdy1, pbh.f_ora_checkbox1, pbh.f_gcbz, sle.fname as f_xsy, pbh.f_khjqnew, pbh.f_shdd, pbh.f_yebz, pbh.fbggysyy, pbh.fjsfsjjq, pbh.fhttk13, pbh.fhttk510, pbh.f_cty_baseproperty1, pbh.f_cty_baseproperty2, pbh.fwcl, pbh.fzzqrjq, pbh.f_gyszh, bld.name as f_settle_curr_id, bldy.name as f_exchange_type_id, pbh.f_exchange_rate, pbh.f_price_list_id, pbh.f_price_time_point, pbh.f_discount_list_id, pbh.f_deposit_ratio, pbh.f_deposit, pbh.f_all_discount, pbh.f_is_included_tax, pbh.f_is_price_exclude_tax, pbh.f_bill_amount, pbh.f_bill_tax_amount, pbh.f_bill_all_amount, bldy.name as f_local_curr_id, pbh.f_bill_amount_lc, pbh.f_bill_tax_amount_lc, pbh.f_bill_all_amount_lc, pbh.f_all_pay_apply_amount, pbh.f_all_pay_amount, pbh.f_all_apply_no_pay_amount, pbh.f_all_refund_amount, pbh.f_all_no_pay_amount, pbh.f_all_appy_no_pay_amount, pbh.f_pay_condition_id FROM po_order_bill_head pbh LEFT JOIN supplier sr on pbh.fsupplier_id=sr.supplierid LEFT JOIN supplier ser on pbh.fsettle_id=ser.supplierid LEFT JOIN supplier spr on pbh.fcharge_id=spr.supplierid LEFT JOIN sys_user su on pbh.fcreator_id=su.k3_key LEFT JOIN bymaterial_dictionary bd on pbh.fbill_type_id=bd.kingdee LEFT JOIN bymaterial_dictionary bld on pbh.f_settle_curr_id=bld.kingdee and bld.category='currency' LEFT JOIN bymaterial_dictionary bldy on pbh.f_local_curr_id=bldy.kingdee and bldy.category='currency' LEFT JOIN supplier_contact sc on pbh.fprovider_contact_id=sc.defaultContact LEFT JOIN sys_employee se on pbh.f_gdy1=se.salesman_id LEFT JOIN sys_employee sle on pbh.f_xsy=sle.salesman_id
AND fid = #{poOrderBillHead.fid} AND f_bill_no = #{poOrderBillHead.fbillNo} AND f_date = #{poOrderBillHead.fdate} AND f_business_type = #{poOrderBillHead.fbusinessType} AND f_bill_type_id = #{poOrderBillHead.fbillTypeId} AND f_supplier_id = #{poOrderBillHead.fsupplierId} AND f_creator_id = #{poOrderBillHead.fcreatorId} AND fcreate_date = #{poOrderBillHead.fcreateDate} AND f_close_status = #{poOrderBillHead.fcloseStatus} AND f_gyszh = #{poOrderBillHead.fGyszh} AND f_acct_type = #{poOrderBillHead.facctype} AND f_gdy1 = #{poOrderBillHead.fGdy1} AND f_ora_date = #{poOrderBillHead.fOraDate} AND f_pay_condition_id = #{poOrderBillHead.fPayConditionId} AND f_xsy = #{poOrderBillHead.fXsy} AND f_khjqnew = #{poOrderBillHead.fKhjqnew} AND f_all_refund_amount = #{poOrderBillHead.fAllRefundAmount} AND f_all_no_pay_amount = #{poOrderBillHead.fAllNoPayAmount} AND f_bill_amount = #{poOrderBillHead.fBillAmount} AND f_bill_all_amount_lc = #{poOrderBillHead.FBillAllAmount_LC}
ORDER BY pbh.fcreate_date DESC
